import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import JobService from '../services/JobService';
import AuthService from '../services/AuthService';
import axios from 'axios';

function JobDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [job, setJob] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [applying, setApplying] = useState(false);
  const [applied, setApplied] = useState(false);

  useEffect(() => {
    fetchJobDetails();
  }, [id]);

  const fetchJobDetails = async () => {
    try {
      const response = await JobService.getJobById(id);
      setJob(response.data);
      setLoading(false);
      // Check if user already applied
      checkIfApplied();
    } catch (err) {
      setError('Không thể tải thông tin công việc');
      setLoading(false);
    }
  };

  const checkIfApplied = async () => {
    try {
      // This endpoint will be created in next step
      const response = await axios.get(`http://localhost:8080/api/applications/check/${id}`, {
        headers: {
          'Authorization': 'Bearer ' + AuthService.getToken()
        }
      });
      setApplied(response.data.applied);
    } catch (err) {
      // Not applied yet or error
    }
  };

  const handleApply = async () => {
    if (!AuthService.isLoggedIn()) {
      navigate('/login');
      return;
    }

    setApplying(true);
    try {
      await axios.post(
        `http://localhost:8080/api/applications/apply/${id}`,
        {},
        {
          headers: {
            'Authorization': 'Bearer ' + AuthService.getToken()
          }
        }
      );
      setApplied(true);
      alert('Ứng tuyển thành công! Hãy kiểm tra trang "Đơn ứng tuyển của tôi"');
    } catch (err) {
      setError(err.response?.data?.message || 'Lỗi khi ứng tuyển');
    } finally {
      setApplying(false);
    }
  };

  if (loading) {
    return <div className="container"><p>Đang tải...</p></div>;
  }

  if (error) {
    return <div className="container"><p className="alert alert-danger">{error}</p></div>;
  }

  if (!job) {
    return <div className="container"><p>Không tìm thấy công việc</p></div>;
  }

  return (
    <div className="container job-details-page">
      <button className="btn btn-secondary" onClick={() => navigate('/jobs')}>← Quay lại</button>

      <div className="job-details-content">
        <div className="job-header">
          <div className="job-title-section">
            <h1>{job.title}</h1>
            <p className="employer-name">Công ty: {job.employer?.username || 'N/A'}</p>
          </div>

          {applied ? (
            <button className="btn btn-success" disabled>✓ Đã ứng tuyển</button>
          ) : (
            <button
              className="btn btn-primary"
              onClick={handleApply}
              disabled={applying}
            >
              {applying ? 'Đang xử lý...' : 'Ứng Tuyển Ngay'}
            </button>
          )}
        </div>

        <div className="job-meta">
          <div className="meta-item">
            <strong>📍 Địa điểm:</strong> {job.location || 'N/A'}
          </div>
          <div className="meta-item">
            <strong>💼 Loại hình:</strong> {job.employmentType || 'N/A'}
          </div>
          <div className="meta-item">
            <strong>💰 Mức lương:</strong> {job.salary ? `$${job.salary.toLocaleString()}` : 'Thỏa thuận'}
          </div>
          <div className="meta-item">
            <strong>📅 Đăng ngày:</strong> {new Date(job.createdAt).toLocaleDateString('vi-VN')}
          </div>
        </div>

        <div className="job-description">
          <h2>Mô Tả Công Việc</h2>
          <p>{job.description}</p>
        </div>

        <div className="job-requirements">
          <h2>Yêu Cầu</h2>
          <ul>
            <li>Kỹ năng và kinh nghiệm liên quan</li>
            <li>Hồ sơ hoàn chỉnh</li>
            <li>Tư duy chuyên nghiệp</li>
          </ul>
        </div>

        <div className="job-actions">
          {applied ? (
            <p className="alert alert-success">
              ✓ Bạn đã ứng tuyển cho công việc này. Chúng tôi sẽ liên hệ với bạn sớm.
            </p>
          ) : (
            <button
              className="btn btn-primary btn-large"
              onClick={handleApply}
              disabled={applying}
            >
              {applying ? 'Đang xử lý...' : 'Ứng Tuyển'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

export default JobDetails;
